create or replace function public.create_stock_count(p_organization_id uuid,p_branch_id uuid,p_warehouse_id uuid,p_count_date date,p_notes text,p_actor_id uuid) returns jsonb language plpgsql security definer set search_path='' as $$ declare v_id uuid; v_no text; begin if p_actor_id is distinct from auth.uid() then raise exception 'Actor mismatch'; end if; if not public.has_org_role(p_organization_id,array['owner','admin','inventory','manager']::public.app_role[]) then raise exception 'Insufficient inventory permission'; end if; if not exists(select 1 from public.warehouses where id=p_warehouse_id and organization_id=p_organization_id and is_active) then raise exception 'Warehouse not found'; end if; v_no:=public.next_document_number(p_organization_id,'CNT'); insert into public.stock_counts(organization_id,branch_id,warehouse_id,count_number,count_date,status,notes,created_by) values(p_organization_id,p_branch_id,p_warehouse_id,v_no,coalesce(p_count_date,current_date),'in_progress',nullif(trim(p_notes),''),p_actor_id) returning id into v_id; insert into public.stock_count_items(organization_id,stock_count_id,product_id,system_quantity,unit_cost) select p_organization_id,v_id,p.id,coalesce(sb.quantity,0),coalesce(p.cost_price,0) from public.products p left join public.stock_balances sb on sb.product_id=p.id and sb.warehouse_id=p_warehouse_id where p.organization_id=p_organization_id and p.is_active; insert into public.audit_events(organization_id,actor_id,action,entity_type,entity_id,metadata) values(p_organization_id,p_actor_id,'inventory.count.started','stock_count',v_id,jsonb_build_object('number',v_no)); return jsonb_build_object('id',v_id,'number',v_no); end $$;

create or replace function public.submit_stock_count(p_organization_id uuid,p_stock_count_id uuid,p_lines jsonb,p_actor_id uuid) returns jsonb language plpgsql security definer set search_path='' as $$ declare c public.stock_counts%rowtype; line jsonb; v_counted numeric; begin if p_actor_id is distinct from auth.uid() then raise exception 'Actor mismatch'; end if; if not public.has_org_role(p_organization_id,array['owner','admin','inventory','manager']::public.app_role[]) then raise exception 'Insufficient inventory permission'; end if; select * into c from public.stock_counts where id=p_stock_count_id and organization_id=p_organization_id for update; if not found or c.status not in ('in_progress','draft') then raise exception 'Stock count is not editable'; end if; if jsonb_typeof(p_lines)<>'array' or jsonb_array_length(p_lines)=0 then raise exception 'Count requires lines'; end if; for line in select value from jsonb_array_elements(p_lines) loop v_counted:=coalesce((line->>'countedQuantity')::numeric,-1); if v_counted<0 then raise exception 'Counted quantity cannot be negative'; end if; update public.stock_count_items set counted_quantity=v_counted where id=(line->>'stockCountItemId')::uuid and stock_count_id=c.id and organization_id=p_organization_id; if not found then raise exception 'Stock count line not found'; end if; end loop; update public.stock_counts set status='submitted',submitted_by=p_actor_id,updated_at=now() where id=c.id; insert into public.audit_events(organization_id,actor_id,action,entity_type,entity_id,metadata) values(p_organization_id,p_actor_id,'inventory.count.submitted','stock_count',c.id,jsonb_build_object('number',c.count_number)); return jsonb_build_object('id',c.id,'number',c.count_number); end $$;

create or replace function public.post_stock_count(p_organization_id uuid,p_stock_count_id uuid,p_actor_id uuid) returns jsonb language plpgsql security definer set search_path='' as $$ declare c public.stock_counts%rowtype; i public.stock_count_items%rowtype; result jsonb; adjustment_count integer:=0; begin if p_actor_id is distinct from auth.uid() then raise exception 'Actor mismatch'; end if; if not public.has_org_role(p_organization_id,array['owner','admin','accountant','inventory']::public.app_role[]) then raise exception 'Insufficient stock count posting permission'; end if; select * into c from public.stock_counts where id=p_stock_count_id and organization_id=p_organization_id for update; if not found or c.status<>'submitted' then raise exception 'Submitted stock count not found'; end if; for i in select * from public.stock_count_items where stock_count_id=c.id and counted_quantity is not null and variance_quantity<>0 order by created_at loop result:=public.post_inventory_adjustment(p_organization_id,c.branch_id,c.warehouse_id,i.product_id,case when i.variance_quantity>0 then 'increase' else 'decrease' end,abs(i.variance_quantity),c.count_date,'Stock count '||c.count_number,c.id,p_actor_id); update public.stock_count_items set posted_adjustment_id=(result->>'id')::uuid where id=i.id; adjustment_count:=adjustment_count+1; end loop; update public.stock_counts set status='posted',posted_by=p_actor_id,posted_at=now(),updated_at=now() where id=c.id; insert into public.audit_events(organization_id,actor_id,action,entity_type,entity_id,metadata) values(p_organization_id,p_actor_id,'inventory.count.posted','stock_count',c.id,jsonb_build_object('number',c.count_number,'adjustments',adjustment_count)); return jsonb_build_object('id',c.id,'number',c.count_number,'adjustments',adjustment_count); end $$;

create or replace function public.register_inventory_tracking(p_organization_id uuid,p_product_id uuid,p_warehouse_id uuid,p_lot_number text,p_manufacture_date date,p_expiry_date date,p_quantity numeric,p_serial_numbers jsonb,p_actor_id uuid) returns jsonb language plpgsql security definer set search_path='' as $$ declare v_lot uuid; serial text; serial_count integer:=0; begin if p_actor_id is distinct from auth.uid() then raise exception 'Actor mismatch'; end if; if not public.has_org_role(p_organization_id,array['owner','admin','inventory','manager']::public.app_role[]) then raise exception 'Insufficient inventory permission'; end if; if not exists(select 1 from public.products where id=p_product_id and organization_id=p_organization_id and is_active) or not exists(select 1 from public.warehouses where id=p_warehouse_id and organization_id=p_organization_id and is_active) then raise exception 'Product or warehouse not found'; end if; if nullif(trim(p_lot_number),'') is not null then insert into public.inventory_lots(organization_id,product_id,warehouse_id,lot_number,manufacture_date,expiry_date,quantity,status) values(p_organization_id,p_product_id,p_warehouse_id,trim(p_lot_number),p_manufacture_date,p_expiry_date,greatest(coalesce(p_quantity,0),0),case when p_expiry_date is not null and p_expiry_date<current_date then 'expired' else 'active' end) on conflict(organization_id,product_id,warehouse_id,lot_number) do update set manufacture_date=excluded.manufacture_date,expiry_date=excluded.expiry_date,quantity=excluded.quantity,status=excluded.status,updated_at=now() returning id into v_lot; end if; if p_serial_numbers is not null and jsonb_typeof(p_serial_numbers)='array' then for serial in select jsonb_array_elements_text(p_serial_numbers) loop if nullif(trim(serial),'') is not null then insert into public.inventory_serials(organization_id,product_id,warehouse_id,serial_number,lot_id,status,source_type) values(p_organization_id,p_product_id,p_warehouse_id,trim(serial),v_lot,'available','manual_registration') on conflict(organization_id,serial_number) do update set product_id=excluded.product_id,warehouse_id=excluded.warehouse_id,lot_id=excluded.lot_id,status='available',updated_at=now(); serial_count:=serial_count+1; end if; end loop; end if; insert into public.audit_events(organization_id,actor_id,action,entity_type,entity_id,metadata) values(p_organization_id,p_actor_id,'inventory.tracking.registered','product',p_product_id,jsonb_build_object('lot',p_lot_number,'serials',serial_count)); return jsonb_build_object('id',coalesce(v_lot,p_product_id),'number',coalesce(nullif(trim(p_lot_number),''),serial_count::text),'serials',serial_count); end $$;

revoke all on function public.create_stock_count(uuid,uuid,uuid,date,text,uuid) from public; grant execute on function public.create_stock_count(uuid,uuid,uuid,date,text,uuid) to authenticated;
revoke all on function public.submit_stock_count(uuid,uuid,jsonb,uuid) from public; grant execute on function public.submit_stock_count(uuid,uuid,jsonb,uuid) to authenticated;
revoke all on function public.post_stock_count(uuid,uuid,uuid) from public; grant execute on function public.post_stock_count(uuid,uuid,uuid) to authenticated;
revoke all on function public.register_inventory_tracking(uuid,uuid,uuid,text,date,date,numeric,jsonb,uuid) from public; grant execute on function public.register_inventory_tracking(uuid,uuid,uuid,text,date,date,numeric,jsonb,uuid) to authenticated;